import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { useParams, useNavigate, useSearchParams } from 'react-router-dom';
import { ArrowLeft, Eye, FileText, Filter, MapPin } from 'lucide-react';

import { DataTable } from '../../components/ui/DataTable';
import { Button } from '../../components/common/Button';
import { getApplicationsForPost } from '../../services/admin.service';
import { getDistricts } from '../../services/master.service';
import DocumentVerificationModal from '../../components/common/DocumentVerificationModal';
import DropdownSearch from '../../components/common/DropdownSearch';
import toast from 'react-hot-toast';
import { cn } from '../../utils/cn';
import { useFloatingTooltip } from '../../hooks/useFloatingTooltip.jsx';

const statusColors = {
    ELIGIBLE: "bg-green-100 text-green-700",
    NOT_ELIGIBLE: "bg-red-100 text-red-700",
    ON_HOLD: "bg-amber-100 text-amber-700",
    PROVISIONAL_SELECTED: "bg-yellow-100 text-yellow-700",
    SELECTED: "bg-emerald-100 text-emerald-700",
    SELECTED_IN_OTHER_POST: "bg-purple-100 text-purple-700",
    REJECTED: "bg-red-200 text-red-800",
};
const statusTabColors = {
    ELIGIBLE:               { active: 'bg-emerald-600 text-white shadow-md',          inactive: 'bg-white border border-emerald-200 text-emerald-700 hover:bg-emerald-50' },
    ON_HOLD:                { active: 'bg-amber-500 text-white shadow-md',            inactive: 'bg-white border border-amber-200 text-amber-700 hover:bg-amber-50' },
    PROVISIONAL_SELECTED:   { active: 'bg-yellow-500 text-white shadow-md',           inactive: 'bg-white border border-yellow-200 text-yellow-700 hover:bg-yellow-50' },
    SELECTED:               { active: 'bg-teal-600 text-white shadow-md',             inactive: 'bg-white border border-teal-200 text-teal-700 hover:bg-teal-50' },
    SELECTED_IN_OTHER_POST: { active: 'bg-purple-600 text-white shadow-md',           inactive: 'bg-white border border-purple-200 text-purple-700 hover:bg-purple-50' },
    REJECTED:               { active: 'bg-rose-600 text-white shadow-md',             inactive: 'bg-white border border-rose-200 text-rose-700 hover:bg-rose-50' },
};

const PostApplications = () => {
    const { postId } = useParams();
    const navigate = useNavigate();
    const [searchParams] = useSearchParams();

    const [applications, setApplications] = useState([]);
    const [loading, setLoading] = useState(true);
    const [statusSummary, setStatusSummary] = useState({});
    const [pagination, setPagination] = useState({ page: 1, limit: 50, total: 0, totalPages: 1 });
    const [postDetails, setPostDetails] = useState(null);
    const [batchInfo, setBatchInfo] = useState(null);

    // Filters
    const [statusFilter, setStatusFilter] = useState('ELIGIBLE');
    const [districtFilter, setDistrictFilter] = useState('');
    const [searchQuery, setSearchQuery] = useState('');
    const [districts, setDistricts] = useState([]);

    // Document verification modal
    const [docVerificationModal, setDocVerificationModal] = useState({ isOpen: false, applicationId: null });

    const { showTooltip, scheduleHideTooltip, renderTooltip } = useFloatingTooltip();

    // Load districts
    useEffect(() => {
        const loadDistricts = async () => {
            try {
                const res = await getDistricts({ is_active: true });
                setDistricts(Array.isArray(res) ? res : res.districts || []);
            } catch (e) {
                console.error('Failed to load districts', e);
            }
        };
        loadDistricts();
    }, []);

    // Fetch applications
    const fetchApplications = async () => {
        setLoading(true);
        try {
            const result = await getApplicationsForPost(postId, {
                status: statusFilter,
                district_id: districtFilter || undefined,
                search: searchQuery || undefined,
                page: pagination.page,
                limit: pagination.limit
            });

            setApplications(result.applications || []);
            setStatusSummary(result.statusSummary || {});
            setPostDetails(result.post || null);
            setBatchInfo(result.batchInfo || null);

            setPagination(prev => ({
                ...prev,
                total: result.pagination?.total || 0,
                totalPages: result.pagination?.totalPages || 1
            }));
        } catch (error) {
            toast.error('Failed to load applications');
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchApplications();
    }, [postId, statusFilter, districtFilter, searchQuery, pagination.page, pagination.limit]);

    const formatMonths = (months = 0) => {
        if (!months) return '—';
        const years = Math.floor(months / 12);
        const rem = months % 12;
        if (years && rem) return `${years}y ${rem}m`;
        if (years) return `${years}y`;
        return `${rem}m`;
    };

    const buildEducationSummary = (education = []) => {
    if (!education.length) {
        return ['No education records'];
    }
    const sorted = [...education].sort(
        (a, b) => (b.educationLevel?.display_order ?? 0) - (a.educationLevel?.display_order ?? 0)
    );
    return sorted.slice(0, 3).map((edu) => {
        const level = edu.educationLevel?.level_name || '';
        const degree = edu.degree_name || '';
        const stream = edu.stream_subject || '';
        const year = edu.passing_year ? `• ${edu.passing_year}` : '';
        const percentage = edu.percentage ? `• ${edu.percentage}%` : '';
        const title = [level, degree].filter(Boolean).join(' • ');
        return `${title}${stream ? ` • ${stream}` : ''} ${year} ${percentage}`.trim();
    });
};

    const buildExperienceSummary = (experience = []) => {
        if (!experience.length) {
            return ['No experience records'];
        }
        const sorted = [...experience].sort(
            (a, b) => (b.start_date ? new Date(b.start_date).getTime() : 0) - (a.start_date ? new Date(a.start_date).getTime() : 0)
        );
        return sorted.slice(0, 3).map((exp) => {
            const role = exp.designation || 'Role';
            const org = exp.organization_name || 'Organisation';
            const duration = formatMonths(exp.total_months);
            const status = exp.is_current ? '• Current' : '';
            return `${role} @ ${org} • ${duration} ${status}`.trim();
        });
    };

    const buildApplicantTooltipContent = useCallback((educationSummary, experienceSummary, applicationId) => (
        <div className="p-4 space-y-3 text-sm text-slate-700">
            <div>
                <p className="text-xs font-semibold uppercase tracking-wide text-slate-500 mb-1">Top Education</p>
                <ul className="space-y-1">
                    {educationSummary.map((item, idx) => (
                        <li key={`edu-${applicationId}-${idx}`} className="flex gap-2">
                            <span className="text-slate-400">•</span>
                            <span>{item}</span>
                        </li>
                    ))}
                </ul>
            </div>
            <div className="border-t border-slate-100 pt-2">
                <p className="text-xs font-semibold uppercase tracking-wide text-slate-500 mb-1">Experience</p>
                <ul className="space-y-1">
                    {experienceSummary.map((item, idx) => (
                        <li key={`exp-${applicationId}-${idx}`} className="flex gap-2">
                            <span className="text-slate-400">•</span>
                            <span>{item}</span>
                        </li>
                    ))}
                </ul>
            </div>
        </div>
    ), []);

    const renderApplicantCell = useCallback((_, application = {}) => {
        const name = application?.applicant?.personal?.full_name || '-';
        const educationSummary = buildEducationSummary(application?.applicant?.education);
        const experienceSummary = buildExperienceSummary(application?.applicant?.experience);
        const appId = application?.application_id;

        return (
            <div
                className="cursor-pointer font-medium text-slate-900"
                onMouseEnter={(event) => appId && showTooltip(event.currentTarget, buildApplicantTooltipContent(educationSummary, experienceSummary, appId), { width: 320, estimatedHeight: 260 })}
                onMouseLeave={scheduleHideTooltip}
                onFocus={(event) => appId && showTooltip(event.currentTarget, buildApplicantTooltipContent(educationSummary, experienceSummary, appId), { width: 320, estimatedHeight: 260 })}
                onBlur={scheduleHideTooltip}
                tabIndex={0}
            >
                {name}
            </div>
        );
    }, [buildApplicantTooltipContent, scheduleHideTooltip, showTooltip]);

    const buildApplicationCountTooltipContent = useCallback((application) => {
        const totalApps = application?.applicant_total_applications ?? 0;
        const otherApps = application?.applicant_other_applications || [];

        return (
            <div className="p-4 space-y-3 text-sm text-slate-700">
                <div className="flex items-center justify-between">
                    <p className="text-xs font-semibold uppercase tracking-wide text-slate-500">
                        Total Applications
                    </p>
                    <span className="text-base font-semibold text-slate-900">{totalApps}</span>
                </div>
                <div className="border-t border-slate-100 pt-2">
                    <p className="text-xs font-semibold uppercase tracking-wide text-slate-500 mb-2">
                        Other Applied Posts ({otherApps.length})
                    </p>
                    {otherApps.length > 0 ? (
                        <ul className="space-y-2 max-h-64 overflow-y-auto">
                            {otherApps.map((app, idx) => (
                                <li key={`other-app-${application.application_id}-${idx}`} className="border-b border-slate-100 pb-2 last:border-0">
                                    <div className="flex flex-col gap-1">
                                        <div className="flex items-center justify-between gap-2">
                                            <span className="font-medium text-slate-900 truncate">{app.post_name || 'N/A'}</span>
                                            <span className={`text-xs px-2 py-0.5 rounded-full ${statusColors[app.status] || 'bg-gray-100 text-gray-700'}`}>
                                                {app.status?.replace(/_/g, ' ')}
                                            </span>
                                        </div>
                                        <div className="text-xs text-slate-500 flex flex-wrap gap-2">
                                            <span>App No: {app.application_no || 'N/A'}</span>
                                            {app.post_code && <span>Code: {app.post_code}</span>}
                                        </div>
                                        {app.district_name && (
                                            <div className="text-xs text-slate-500">
                                                District: {app.district_name}
                                            </div>
                                        )}
                                    </div>
                                </li>
                            ))}
                        </ul>
                    ) : (
                        <p className="text-xs text-slate-500 italic">
                            {totalApps > 1
                                ? 'Other applications data not available'
                                : 'No applications in other posts'}
                        </p>
                    )}
                </div>
            </div>
        );
    }, []);

    const renderApplicationCountCell = useCallback((_, application = {}) => {
        const totalApps = application?.applicant_total_applications ?? 0;

        return (
            <div
                className="flex justify-center"
                onMouseEnter={(event) => showTooltip(event.currentTarget, buildApplicationCountTooltipContent(application), { width: 384, estimatedHeight: 260 })}
                onMouseLeave={scheduleHideTooltip}
                onFocus={(event) => showTooltip(event.currentTarget, buildApplicationCountTooltipContent(application), { width: 384, estimatedHeight: 260 })}
                onBlur={scheduleHideTooltip}
                tabIndex={0}
            >
                <span
                    className={cn(
                        "inline-flex min-w-[2.5rem] items-center justify-center rounded-full px-3 py-1 text-sm font-semibold transition-colors",
                        totalApps > 1
                            ? "bg-blue-50 text-blue-700 border border-blue-200"
                            : "bg-slate-100 text-slate-700 border border-transparent"
                    )}
                >
                    {totalApps}
                </span>
            </div>
        );
    }, [buildApplicationCountTooltipContent, scheduleHideTooltip, showTooltip]);

    const columns = useMemo(() => [
        {
            key: 'application_no',
            header: 'App No',
            sortable: true
        },
        {
            key: 'applicant',
            header: 'Applicant',
            className: 'relative overflow-visible',
            render: renderApplicantCell,
        },
        {
            key: 'total_applications',
            header: 'Total Posts',
            className: 'relative overflow-visible text-center',
            render: renderApplicationCountCell,
        },
        {
            key: 'district',
            header: 'District',
            render: (_, row = {}) =>
                row?.applicant?.address?.permanentDistrict?.district_name || '-',

        },
        {
            key: 'status',
            header: 'Status',
            render: (_, row = {}) => (
                <span className={`inline-flex rounded-full px-2 py-1 text-xs font-medium ${statusColors[row.status] || 'bg-gray-100'}`}>
                    {row.status?.replace(/_/g, ' ')}
                </span>
            ),
        },
        {
            key: 'actions',
            header: 'Actions',
            render: (_value, row = {}) => (
                <div className="flex gap-1">
                    <Button
                        variant="ghost"
                        size="sm"
                        onClick={() => row.application_id && navigate(`/applications/${row.application_id}`)}
                        title="View Details"
                    >
                        <Eye className="h-4 w-4" />
                    </Button>
                    <Button
                        variant="ghost"
                        size="sm"
                        onClick={() => row.application_id && setDocVerificationModal({ isOpen: true, applicationId: row.application_id })}
                        title="Verify Documents"
                    >
                        <FileText className="h-4 w-4" />
                    </Button>
                </div>
            ),
        },
    ], [navigate, renderApplicantCell, renderApplicationCountCell]);

    const handleTableSearch = useCallback((value) => {
        setPagination(prev => ({ ...prev, page: 1 }));
        setSearchQuery((value || '').trim());
    }, []);
    // Convert districts → DropdownSearch options format
    const districtOptions = districts.map(d => ({
        id: d.district_id,
        name: d.district_name,
    }));

    return (
        <div className="space-y-6">
            {/* Header */}
            <div className="space-y-4">
                <div className="flex items-center gap-3">
                    <Button variant="ghost" size="sm" onClick={() => navigate('/review')}>
                        <ArrowLeft className="h-5 w-5" />
                    </Button>
                    <div>
                        <h1 className="text-2xl font-bold text-slate-900">Review Applications</h1>
                        <p className="text-sm text-slate-500 mt-1">
                            Applications ordered by merit score
                        </p>
                    </div>
                </div>

                {postDetails && (
                    <div className="rounded-2xl border border-slate-200 bg-white p-4 md:p-6 shadow-md">
                        <div className="text-[11px] font-bold uppercase tracking-widest text-slate-400 mb-3">Current Post</div>
                        <div className="mt-2 flex flex-col md:flex-row md:items-baseline md:justify-between gap-4">
                            <div>
                                <div className="text-3xl font-bold text-slate-900">{postDetails.post_name}</div>
                                <div className="mt-1 text-base text-slate-600">
                                    {postDetails.component?.component_name ? `${postDetails.component.component_name} • ` : ''}
                                    {postDetails.district?.district_name || 'All Districts'}
                                </div>
                            </div>
                            <div className="grid grid-cols-2 sm:grid-cols-3 gap-3 text-sm text-slate-600">
                                <div className="rounded-xl bg-slate-50 border border-slate-200 px-3 py-2 shadow-sm">
                                    <div className="text-xs uppercase text-slate-400 font-medium">Post Code</div>
                                    <div className="text-base font-semibold text-slate-900">{postDetails.post_code || '—'}</div>
                                </div>
                                <div className="rounded-xl bg-blue-50 border border-blue-100 px-3 py-2 shadow-sm">
                                    <div className="text-xs uppercase text-blue-400 font-medium">Applications</div>
                                    <div className="text-base font-semibold text-blue-700">{pagination.total}</div>
                                </div>
                                <div className="rounded-xl bg-slate-50 border border-slate-200 px-3 py-2 shadow-sm">
                                    <div className="text-xs uppercase text-slate-400 font-medium">Status View</div>
                                    <div className="text-base font-semibold text-slate-900">{statusFilter.replace(/_/g, ' ')}</div>
                                </div>
                            </div>
                        </div>
                    </div>
                )}
            </div>

            {/* Status Summary Tabs */}
            <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
                <div className="flex gap-2 flex-wrap">
                    {['ELIGIBLE', 'ON_HOLD', 'PROVISIONAL_SELECTED', 'SELECTED', 'SELECTED_IN_OTHER_POST', 'REJECTED'].map(s => {
                        const colors = statusTabColors[s] || { active: 'bg-blue-600 text-white shadow-md', inactive: 'bg-white border border-slate-200 text-slate-600 hover:border-blue-300' };
                        return (
                            <button
                                key={s}
                                onClick={() => {
                                    setStatusFilter(s);
                                    setPagination(p => ({ ...p, page: 1 }));
                                }}
                                className={`px-4 py-2 rounded-xl text-sm font-medium transition-all duration-150 ${statusFilter === s ? colors.active : colors.inactive}`}
                            >
                                {s.replace('_', ' ')} ({statusSummary[s] || 0})
                            </button>
                        );
                    })}
                </div>

                {/* District Filter — DropdownSearch */}
                <div className="flex items-center gap-2">
                    <Filter className="w-4 h-4 text-slate-400" />
                    <DropdownSearch
                        value={districtFilter}
                        onChange={(e) => {
                            setDistrictFilter(e.target.value);
                            setPagination(p => ({ ...p, page: 1 }));
                        }}
                        options={districtOptions}
                        placeholder="All Districts"
                        icon={MapPin}
                    />
                </div>
            </div>

            {/* Batch Info Display */}
            {batchInfo && (
                <div className={`p-4 rounded-lg border ${
                    batchInfo.is_filtered 
                        ? 'bg-blue-50 border-blue-200' 
                        : 'bg-slate-50 border-slate-200'
                }`}>
                    <div className="flex items-center justify-between">
                        <div>
                            <h3 className={`font-semibold ${
                                batchInfo.is_filtered ? 'text-blue-900' : 'text-slate-900'
                            }`}>
                                {batchInfo.is_filtered ? 'Your Assigned Batch' : 'No Batch Assignment'}
                            </h3>
                            {batchInfo.is_filtered ? (
                                <p className="text-sm text-blue-700 mt-1">
                                    You are reviewing ranks <strong>{batchInfo.batch_start}</strong> to <strong>{batchInfo.batch_end}</strong>
                                    {' '}({batchInfo.batch_size} applicants total)
                                </p>
                            ) : (
                                <p className="text-sm text-slate-600 mt-1">
                                    You can see all applications. Contact admin to assign a batch.
                                </p>
                            )}
                        </div>
                        {batchInfo.note && (
                            <div className="text-xs text-slate-500 italic">
                                {batchInfo.note}
                            </div>
                        )}
                    </div>
                </div>
            )}

            {/* Data Table */}
            <DataTable
                columns={columns}
                data={applications}
                onSearch={handleTableSearch}
                pagination={{
                    currentPage: pagination.page,
                    totalPages: pagination.totalPages,
                    onPageChange: (p) => setPagination(prev => ({ ...prev, page: p })),
                    pageSize: pagination.limit,
                    onPageSizeChange: (l) => setPagination(prev => ({ ...prev, limit: l, page: 1 })),
                    pageSizeOptions: [20, 50, 100],
                }}
                isLoading={loading}
                rowKey="application_id"
                enableSelection={false}
                headerClassName="bg-slate-900 text-white"
            />

            {/* Document Verification Modal */}
            <DocumentVerificationModal
                isOpen={docVerificationModal.isOpen}
                onClose={() => setDocVerificationModal({ isOpen: false, applicationId: null })}
                applicationId={docVerificationModal.applicationId}
                onVerificationComplete={() => {
                    fetchApplications();
                }}
            />

            {renderTooltip()}
        </div>
    );
};

export default PostApplications;